INSERT INTO course_details (course_id, entry_requirements, admission_test_info, interview_info, documents_required, personal_statement_guidelines, additional_info)
VALUES 
('acfc55c6-6642-439a-bfc8-5a23b17cb404', 'Foundation Year Entry: Applicants must be aged 18+ and have a minimum of a Level 2 qualification or equivalent. Applicants aged 21+ who do not meet standard entry requirements but can demonstrate willingness, commitment and relevant experience are also welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, 'The Foundation Year provides the academic grounding needed to progress onto the full degree programme.'),
('43c4a50d-2cc4-44f7-acd8-313c0d82aa08', 'Foundation Year Entry: Applicants must be aged 18+ and have a minimum of a Level 2 qualification or equivalent. Applicants aged 21+ who do not meet standard entry requirements but can demonstrate willingness, commitment and relevant experience are also welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, 'The Foundation Year provides the academic grounding needed to progress onto the BSc Health, Wellbeing and Social Care programme.'),
('95b17cf0-f73f-40cf-8435-ad7c60487829', 'Foundation Year Entry: Applicants must be aged 18+ and have a minimum of a Level 2 qualification or equivalent. Applicants aged 21+ who do not meet standard entry requirements but can demonstrate willingness, commitment and relevant experience are also welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, 'The Foundation Year provides the academic grounding needed to progress onto the BSc Project Management programme.'),
('64353f03-9f3b-4f2b-8fe3-885dddbc4a47', 'Foundation Year Entry: Applicants must be aged 18+ and have a minimum of a Level 2 qualification or equivalent. Applicants aged 21+ who do not meet standard entry requirements but can demonstrate willingness, commitment and relevant experience are also welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, 'The Foundation Year provides the academic grounding needed to progress onto the BSc Psychology with Counselling programme.'),
('f94754d6-d695-41c9-8002-df2d37b4d07b', 'Foundation Year Entry: Applicants must be aged 18+ and have a minimum of a Level 2 qualification or equivalent. Applicants aged 21+ who do not meet standard entry requirements but can demonstrate willingness, commitment and relevant experience are also welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, 'The Integrated Foundation Year provides the academic grounding needed to progress onto the BSc Psychology with Counselling programme.'),
('836bb6f8-602f-48aa-ba72-f4b6c9badb89', 'Applicants must be aged 18+ and have a Level 3 qualification or an Access to Higher Education certificate. Demonstrate English proficiency: GCSE 4/C or CEFR B2. Applicants aged 21+ who do not match the standard entry requirements but who can demonstrate willingness and commitment are welcome to apply.', 'If you do not have GCSE 4/C or CEFR B2 for English proficiency, you can carry out an English test provided at a GBS campus.', 'A panel interview takes place to assess your application.', 'Supporting documents when requested by GBS.', NULL, '225 hours of placement required. To achieve HNC: complete units equivalent to 120 credits at Level 4 and pass 105 credits. To achieve HND: complete 120 credits at Level 5 and pass 105 credits.')
